import AppKit

/// Type-erased dispatch over the per-kind layout primitives. Holds whichever
/// `XxxLayout` value the block kind required, and exposes the three things
/// downstream code asks for:
///
/// - `totalHeight`(consumed by `NSTableView.heightOfRow`)
/// - `measuredWidth`(used by the diff to detect width changes)
/// - `draw(in:origin:)`(invoked by the cell's `draw(_:)`)
///
/// Add a new layout primitive: add the case here, extend the three methods.
/// The cell view is enum-agnostic — it just calls `layout.draw`.
enum RowLayout: Sendable {
    case text(TextLayout)
    case image(ImageLayout)

    var totalHeight: CGFloat {
        switch self {
        case .text(let l): return l.totalHeight
        case .image(let l): return l.totalHeight
        }
    }

    var measuredWidth: CGFloat {
        switch self {
        case .text(let l): return l.measuredWidth
        case .image(let l): return l.measuredWidth
        }
    }

    func draw(in ctx: CGContext, origin: CGPoint) {
        switch self {
        case .text(let l): l.draw(in: ctx, origin: origin)
        case .image(let l): l.draw(in: ctx, origin: origin)
        }
    }
}

/// One row's prepared state — `Block` (data) + `RowLayout` (geometry at a
/// specific width). Immutable; diff-friendly.
struct RowItem: Equatable, Sendable {
    let id: UUID
    let block: Block
    let layout: RowLayout

    /// Width-aware identity. Same id + same block + same measured width →
    /// the layout result is reusable (no recompute).
    static func == (lhs: RowItem, rhs: RowItem) -> Bool {
        lhs.id == rhs.id && lhs.block == rhs.block
            && lhs.layout.measuredWidth == rhs.layout.measuredWidth
    }
}

import AppKit
import CoreText

/// Immutable Core Text layout — pure function of (attributed string, max width).
///
/// Coordinate system: y grows downward (matches NSTableView's flipped row coords).
/// `lineOrigins[i].y` is the baseline distance from the top of the layout.
///
/// `@unchecked Sendable`: Swift's type system can't see that `CTLine` is
/// thread-safe. Apple's Core Text Programming Guide documents `CTLine` as
/// immutable / safe to share across threads — we promise not to mutate the
/// `[CTLine]` after construction.
struct TextLayout: @unchecked Sendable {
    let lines: [CTLine]
    let lineOrigins: [CGPoint]
    let totalHeight: CGFloat
    let measuredWidth: CGFloat

    static let empty = TextLayout(
        lines: [], lineOrigins: [], totalHeight: 0, measuredWidth: 0)

    static func make(attributed: NSAttributedString, maxWidth: CGFloat) -> TextLayout {
        guard attributed.length > 0, maxWidth > 0 else { return .empty }

        let typesetter = CTTypesetterCreateWithAttributedString(attributed)
        let length = attributed.length
        var lines: [CTLine] = []
        var origins: [CGPoint] = []
        var y: CGFloat = 0
        var start: CFIndex = 0

        while start < length {
            let count = CTTypesetterSuggestLineBreak(typesetter, start, Double(maxWidth))
            guard count > 0 else { break }
            let line = CTTypesetterCreateLine(
                typesetter, CFRange(location: start, length: count))

            var ascent: CGFloat = 0
            var descent: CGFloat = 0
            var leading: CGFloat = 0
            _ = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)

            y += ascent
            origins.append(CGPoint(x: 0, y: y))
            y += descent + leading
            lines.append(line)
            start += count
        }

        return TextLayout(
            lines: lines, lineOrigins: origins,
            totalHeight: y, measuredWidth: maxWidth)
    }

    /// Draw into a flipped NSView. `origin` is layout's top-left in view coords.
    func draw(in ctx: CGContext, origin: CGPoint) {
        ctx.saveGState()
        // Flip text matrix so Core Text glyphs render upright in a flipped view.
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        for (line, lineOrigin) in zip(lines, lineOrigins) {
            ctx.textPosition = CGPoint(
                x: origin.x + lineOrigin.x,
                y: origin.y + lineOrigin.y)
            CTLineDraw(line, ctx)
        }
        ctx.restoreGState()
    }
}

import AppKit

/// Immutable image layout — pure function of `(image, maxWidth, maxHeight)`.
///
/// Stores a `CGImage` (not the source `NSImage`):
/// - CGImage is `Sendable` since macOS 13 → ImageLayout is truly Sendable
///   without `@unchecked`, safe to construct off-main and hand to MainActor
/// - One-time bitmap extraction in `make`, not on every `draw` (which the
///   NSImage variant repeated)
///
/// `displayRect.origin` is the aspect-fit rectangle's top-left inside the
/// row's content area. `totalHeight` is what `heightOfRow` consumes.
struct ImageLayout: Sendable {
    let cgImage: CGImage?
    let displayRect: CGRect
    let totalHeight: CGFloat
    let measuredWidth: CGFloat

    static func make(image: NSImage,
                     maxWidth: CGFloat,
                     maxHeight: CGFloat) -> ImageLayout {
        let intrinsic = image.size
        guard maxWidth > 0,
              intrinsic.width > 0,
              intrinsic.height > 0
        else {
            return ImageLayout(cgImage: nil,
                               displayRect: .zero,
                               totalHeight: 0,
                               measuredWidth: max(0, maxWidth))
        }

        // Aspect-fit within (maxWidth × maxHeight). Never upscale.
        let scale = min(1, min(maxWidth / intrinsic.width,
                               maxHeight / intrinsic.height))
        let w = intrinsic.width * scale
        let h = intrinsic.height * scale
        let originX = (maxWidth - w) / 2     // center horizontally

        // Extract CGImage once (off-main safe). Subsequent draws reuse it.
        let cg = image.cgImage(forProposedRect: nil, context: nil, hints: nil)
        return ImageLayout(
            cgImage: cg,
            displayRect: CGRect(x: originX, y: 0, width: w, height: h),
            totalHeight: h,
            measuredWidth: maxWidth)
    }

    /// Draw into a flipped NSView. `origin` is the layout's top-left in view coords.
    func draw(in ctx: CGContext, origin: CGPoint) {
        guard let cgImage,
              displayRect.width > 0, displayRect.height > 0 else { return }
        let target = CGRect(
            x: origin.x + displayRect.minX,
            y: origin.y + displayRect.minY,
            width: displayRect.width,
            height: displayRect.height)
        // CGContext.draw expects y-up image coords; we are in a flipped view,
        // so locally flip around the target rect to keep the bitmap upright.
        ctx.saveGState()
        ctx.translateBy(x: target.minX, y: target.maxY)
        ctx.scaleBy(x: 1, y: -1)
        ctx.draw(cgImage, in: CGRect(x: 0, y: 0,
                                     width: target.width,
                                     height: target.height))
        ctx.restoreGState()
    }
}

