    private var currentpos:ScrollPosition = ScrollPosition()
    public var deltaCorner:Int64 = 60

    public var applyExternalScroll:((NSEvent)->Bool)? = nil

    override public static var isCompatibleWithResponsiveScrolling: Bool {
        return true
